    padding: 2rem 0; // Consistent ultra tight spacing
    background: $background-primary;

    @media (max-width: $breakpoint-md) {
      padding: $space-md 0;
    }

    @media (max-width: $breakpoint-sm) {
      padding: $space-sm 0;
    }
