.section-header {
  text-align: center;
  margin-bottom: $space-3xl; // Generous spacing for breathing room
  position: relative;

  h1 {
    margin-bottom: $space-md; // Much tighter spacing
    font-weight: $font-weight-medium; // Consistent hierarchy (450)
    letter-spacing: -0.04em; // Tighter kerning like boring.industries
    font-family: $font-primary;
    font-size: clamp(2.8rem, 5vw, 4.8rem); // More restrained, boring.industries style
  }

  h2 {
    margin-bottom: $space-md; // Much tighter spacing
    font-weight: $font-weight-regular; // Consistent hierarchy (400)
    letter-spacing: -0.04em; // Tighter kerning like boring.industries
    font-family: $font-primary;
    font-size: clamp(2.8rem, 5vw, 4.8rem); // More restrained, boring.industries style
  }

  .section-intro {
    font-size: $font-size-base; // Smaller, more minimal
    color: $text-tertiary;
    line-height: 1.5; // Tighter line height
    max-width: 50rem; // Narrower for minimal feel
    margin: 0 auto;
    font-weight: $font-weight-regular;
    font-family: $font-primary; // Clean sans-serif
    font-style: normal; // No italic for cleaner look
    letter-spacing: -0.01em; // Tight kerning
  }

  // Blog page specific styling - use accent color
  .section--beige & .section-intro {
    color: $earth-coral;
    font-weight: 500;
  }

  .section-emoji {
    display: none; // Remove emojis for sophistication
  }

