// Grid System
.grid {
  display: grid;
  gap: $space-xl;

  &--2-cols {
    grid-template-columns: repeat(2, 1fr);

    @media (max-width: $breakpoint-md) {
      grid-template-columns: 1fr;
    }
  }

  &--3-cols {
    grid-template-columns: repeat(3, 1fr);

    @media (max-width: $breakpoint-lg) {
      grid-template-columns: repeat(2, 1fr);
    }

    @media (max-width: $breakpoint-sm) {
      grid-template-columns: 1fr;
    }
  }
}

// Container System with Mobile Support
.container {
  max-width: $container-standard;
  margin: 0 auto;
  padding: 0 $space-xl;

  @media (max-width: $breakpoint-md) {
    padding: 0 $space-lg;
  }

  @media (max-width: $breakpoint-sm) {
    padding: 0 $space-md; // Better mobile padding - 16px for readability
  }

  &--narrow {
    max-width: $container-narrow;
  }

  &--wide {
    max-width: $container-wide;
  }

  &--full {
    max-width: $container-full;
  }
}

// Animation Classes
.fade-in {
  opacity: 0;
  transform: translateY(2rem);
  transition: all var(--transition-slow);

  &.visible {
    opacity: 1;
    transform: translateY(0);
  }
}

.stagger-item {
  opacity: 1; // Make visible by default
  transform: translateY(0); // No transform by default
  transition: all 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);

  // Only apply initial hidden state if JavaScript is available and page is loaded
  &.animate-on-load {
    opacity: 0;
    transform: translateY(2rem);

    &:nth-child(1) {
      transition-delay: 0.1s;
    }
    &:nth-child(2) {
      transition-delay: 0.2s;
    }
    &:nth-child(3) {
      transition-delay: 0.3s;
    }
    &:nth-child(4) {
      transition-delay: 0.4s;
    }
  }

  &.visible {
    opacity: 1;
    transform: translateY(0);
  }
}

// Minimal Form Elements - Aligned with Design System
.form-group {
  margin-bottom: $space-lg;

  label {
    display: block;
    font-size: $font-size-small;
    font-weight: $font-weight-medium;
    color: $text-primary;
    margin-bottom: $space-sm;
    letter-spacing: -0.01em; // Consistent with design system
    font-family: $font-primary;
  }

  input,
  textarea {
    width: 100%;
    padding: 1.6rem 2rem; // More generous, sophisticated padding
    border: 1px solid rgba(0, 0, 0, 0.1); // Minimal border
    border-radius: 8px; // Consistent with buttons
    font-size: $font-size-base;
    font-family: $font-primary;
    background: rgba(255, 255, 255, 0.9);
    transition: all var(--transition-base);
    letter-spacing: -0.005em; // Consistent typography

    &:focus {
      outline: none;
      border-color: $earth-coral;
      box-shadow: 0 0 0 3px rgba(184, 118, 94, 0.1);
      background: rgba(255, 255, 255, 1);
      transform: translateY(-1px); // Subtle lift on focus
    }

    &:hover:not(:focus) {
      border-color: rgba(184, 118, 94, 0.2);
      background: rgba(255, 255, 255, 0.95);
    }

    &::placeholder {
      color: $text-quaternary;
      font-style: italic;
    }
  }

  textarea {
    min-height: 12rem;
    resize: vertical;
    line-height: 1.5; // Consistent with body text
  }
}

// Utility Classes
.text-center {
  text-align: center;
}
.text-left {
  text-align: left;
}
.text-right {
  text-align: right;
}

.mb-0 {
  margin-bottom: 0;
}
.mb-sm {
  margin-bottom: var(--space-sm);
}
.mb-md {
  margin-bottom: var(--space-md);
}
.mb-lg {
  margin-bottom: var(--space-lg);
}
.mb-xl {
  margin-bottom: var(--space-xl);
}
.mb-2xl {
  margin-bottom: var(--space-2xl);
}
.mb-3xl {
  margin-bottom: var(--space-3xl);
}

.mt-0 {
  margin-top: 0;
}
.mt-sm {
  margin-top: var(--space-sm);
}
.mt-md {
  margin-top: var(--space-md);
}
.mt-lg {
  margin-top: var(--space-lg);
}
.mt-xl {
  margin-top: var(--space-xl);
}
.mt-2xl {
  margin-top: var(--space-2xl);
}
.mt-3xl {
  margin-top: var(--space-3xl);
}

// Accessibility
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

// Skip to content link for keyboard navigation
.skip-to-content {
  position: fixed;
  top: -100px;
  left: 1rem;
  z-index: 10000;
  padding: 1rem 1.5rem;
  background: $earth-coral;
  color: white;
  font-weight: $font-weight-medium;
  text-decoration: none;
  border-radius: 0 0 0.5rem 0.5rem;
  transition: top 0.3s ease;
  font-size: 1.4rem;

  &:focus {
    top: 0;
    outline: 3px solid #fff;
    outline-offset: 2px;
  }

  &:hover {
    background: #a36952;
    color: white;
    text-decoration: none;
  }
}

// Focus indicators
*:focus {
  outline: 2px solid $clay-orange;
  outline-offset: 2px;
}

// Reduced motion support
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

