      border: 1px solid rgba(184, 118, 94, 0.2);
    }
  }

  .work-tags {
    display: flex;
    gap: $space-xs;
    margin-top: $space-sm;
    flex-wrap: wrap;

    .tag {
      font-size: $font-size-xs;
      font-weight: $font-weight-medium;
      color: $text-tertiary;
      background: rgba(122, 132, 113, 0.08);
      padding: 0.2rem 0.6rem;
      border-radius: 8px;
      border: 1px solid rgba(122, 132, 113, 0.15);
      letter-spacing: 0.02em;
      transition: all var(--transition-fast);
    }
  }

  // Work item type variants
  &.work-item--external {
    .work-status {
      background: rgba(45, 90, 69, 0.1);
      color: #2d5a45;
      border-color: rgba(45, 90, 69, 0.2);
    }
  }

  &.work-item--consulting {
    .work-status {
      background: rgba(184, 118, 94, 0.1);
      color: $earth-coral;
      border-color: rgba(184, 118, 94, 0.2);
    }
  }

  &.work-item--enterprise {
    .work-status {
      background: rgba(155, 144, 136, 0.1);
      color: $earth-stone;
      border-color: rgba(155, 144, 136, 0.2);
    }
  }

  &.work-item--creative {
    .work-status {
      background: rgba(107, 119, 99, 0.1);
      color: $earth-moss;
      border-color: rgba(107, 119, 99, 0.2);
    }
  }

  &:hover {
    .work-indicator .work-icon {
      opacity: 1;
      transform: scale(1.1);
    }

    .work-tags .tag {
      background: rgba(122, 132, 113, 0.12);
      border-color: rgba(122, 132, 113, 0.25);
      color: $text-secondary;
    }
  }
}

// Compact Work Cards - Modern Card Layout
.work-grid--compact {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: $space-xl;
  margin-top: $space-xl;

  @media (min-width: $breakpoint-lg) {
    grid-template-columns: repeat(3, 1fr); // Force 3 columns on desktop
    gap: $space-2xl; // More spacing for luxurious look
  }

  @media (max-width: $breakpoint-md) {
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: $space-md;
  }

  @media (max-width: $breakpoint-sm) {
    grid-template-columns: 1fr;
    gap: $space-md;
  }
}

.work-card {
  position: relative;
  background: $background-primary;
  border: 1px solid $border-light;
  border-radius: 8px;
  padding: $space-md; // Tighter spacing for boring.industries aesthetic (16px)
  transition: all var(--transition-base);
  overflow: hidden;

  &:hover {
    border-color: $border-medium;
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.08);

    .work-card-link::after {
      opacity: 1;
    }
  }

  .work-card-header {
    display: flex;
    justify-content: flex-end;
    margin-bottom: $space-md;
  }

  .work-card-content {
    position: relative;
    z-index: 2;
  }

  .work-card-icon {
    font-size: 3rem;
    margin-bottom: $space-md;
    display: block;
    opacity: 0.8;
  }

  .work-card-title {
    font-family: $font-primary;
    font-size: clamp(1.8rem, 2.5vw, 2.2rem); // Fluid typography like boring.industries
    font-weight: 450; // Consistent lighter weight
    color: $text-primary;
    margin-bottom: $space-sm;
    line-height: 1.25; // Tighter line height
    letter-spacing: -0.025em; // Tighter kerning for sophistication
  }

  .work-card-description {
    font-size: clamp(1.4rem, 1.8vw, 1.6rem); // Fluid scaling
    color: $text-secondary;
    line-height: 1.3; // Ultra-tight line height for boring.industries aesthetic
    margin-bottom: $space-lg;
    letter-spacing: -0.015em; // Refined kerning
    font-weight: 400;
  }

  .work-card-meta {
    display: flex;
    justify-content: space-between;
    align-items: center;

    .work-type {
      font-size: $font-size-xs;
      color: $text-tertiary;
      font-weight: $font-weight-medium;
      text-transform: uppercase;
      letter-spacing: 0.1em;
    }

    .work-year {
      font-size: $font-size-xs;
      color: $text-quaternary;
      font-weight: $font-weight-medium;
    }
  }

  .work-card-link {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: 3;

    &::after {
      content: '';
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: linear-gradient(135deg, rgba(184, 118, 94, 0.02) 0%, rgba(184, 118, 94, 0.04) 100%);
      opacity: 0;
      transition: opacity 0.3s ease;
    }
  }
}

.work-status {
  font-size: $font-size-xs;
  font-weight: $font-weight-medium;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  padding: 0.3rem 0.8rem;
  border-radius: 12px;

  &--active {
    background: rgba(76, 175, 80, 0.1);
    color: #4CAF50;
  }

  &--live {
    background: rgba(184, 118, 94, 0.1);
    color: $earth-coral;
  }

  &--delivered {
    background: rgba(122, 132, 113, 0.1);
    color: $earth-sage;
  }

  &--published {
    background: rgba(107, 119, 99, 0.1);
    color: $earth-moss;
    border-color: rgba(107, 119, 99, 0.2);
  }
}

// About Page Content Grids - Clean & Organized
.expertise-grid,
.philosophy-grid,
.deliverables-grid,
.personal-grid {
  display: grid;
  gap: $space-lg;
  margin-top: $space-xl;

  @media (max-width: $breakpoint-sm) {
    grid-template-columns: 1fr;
    gap: $space-md;
  }
}

.expertise-grid {
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
}

.philosophy-grid,
.deliverables-grid {
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
}

.personal-grid {
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
}

.expertise-item,
.philosophy-item,
.deliverable-item,
.personal-item {
  background: linear-gradient(135deg, rgba(184, 118, 94, 0.03) 0%, rgba(255, 255, 255, 0.8) 100%);
  border: 1px solid rgba(184, 118, 94, 0.08);
  border-radius: 12px;
  padding: 3rem; // More generous padding for better whitespace
  position: relative;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  backdrop-filter: blur(10px);
  margin-bottom: $space-lg; // Better spacing between items
  display: flex;
  align-items: flex-start;
  gap: $space-lg; // Space between icon and content

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 4px;
    height: 100%;
    background: linear-gradient(180deg, $earth-coral 0%, rgba(184, 118, 94, 0.3) 100%);
    border-radius: 2px 0 0 2px;
  }

  strong {
    font-weight: $font-weight-semibold;
    color: $text-primary;
    letter-spacing: -0.015em;
    display: block;
    margin-bottom: $space-xs;
  }

  &:hover {
    transform: translateY(-4px);
    box-shadow: 0 8px 32px rgba(184, 118, 94, 0.12);
    border-color: rgba(184, 118, 94, 0.15);
    background: linear-gradient(135deg, rgba(184, 118, 94, 0.05) 0%, rgba(255, 255, 255, 0.9) 100%);
  }
}

.personal-item {
  background: linear-gradient(135deg, rgba(122, 132, 113, 0.03) 0%, rgba(255, 255, 255, 0.8) 100%);
  border-color: rgba(122, 132, 113, 0.08);

  &::before {
    background: linear-gradient(180deg, $earth-sage 0%, rgba(122, 132, 113, 0.3) 100%);
  }

  &:hover {
    background: linear-gradient(135deg, rgba(122, 132, 113, 0.05) 0%, rgba(255, 255, 255, 0.9) 100%);
    border-color: rgba(122, 132, 113, 0.15);
    box-shadow: 0 8px 32px rgba(122, 132, 113, 0.12);
  }
}

// Fine Art Editorial Blog Posts - Gallery Aesthetic
.post-grid {
  display: flex;
  flex-direction: column;
  gap: 0;

  .post-item {
    padding: $space-xl 0; // More generous spacing
    border-bottom: 1px solid rgba(230, 228, 223, 0.3); // Subtler borders

    &:first-child {
      padding-top: $space-lg;
    }

    &:last-child {
      border-bottom: none;
      padding-bottom: 0;
    }

    .post-link {
      display: block;
      text-decoration: none;
      transition: all var(--transition-base);

      &:hover {
        background: transparent; // Clean hover without background
        transform: translateX(6px); // Subtle shift

        .post-title {
          color: $earth-coral;
          letter-spacing: -0.01em;
        }

        .post-meta {
          opacity: 1;
          color: $earth-coral;
        }
      }
    }

    .post-meta {
      font-size: $font-size-xs;
      color: $text-quaternary;
      font-weight: $font-weight-light; // Lighter for sophistication
      text-transform: uppercase;
      letter-spacing: 0.1em; // More spacing for gallery feel
      margin: 0 0 $space-sm 0;
      opacity: 0.7;
      transition: all var(--transition-base);
      display: flex;
      align-items: center;
      gap: $space-sm;
      flex-wrap: wrap;

      time {
        color: inherit;
      }

      .post-category {
        background: rgba(184, 118, 94, 0.1);
        color: $earth-coral;
        padding: 0.2rem 0.6rem;
        border-radius: 6px;
        font-size: $font-size-xs;
        font-weight: $font-weight-medium;
        text-transform: none;
        letter-spacing: 0.02em;
      }

      .post-reading-time {
        color: $text-quaternary;
        font-weight: $font-weight-regular;
        text-transform: none;
        letter-spacing: 0;
        opacity: 0.6;
      }
    }

    .post-title {
      font-size: $font-size-large; // Larger for presence
      font-weight: $font-weight-light; // Lighter for sophistication
      color: $text-primary;
      margin: 0 0 $space-sm 0;
      line-height: 1.3; // Tighter for editorial feel
      transition: all var(--transition-base);
      font-family: $font-display; // Use display font
      letter-spacing: -0.005em; // Subtle negative tracking
    }

    .post-excerpt {
      font-size: $font-size-base; // Larger for readability
      color: $text-tertiary;
      line-height: 1.6; // More generous line height
      margin: 0 0 $space-sm 0;
      font-weight: $font-weight-regular;
      max-width: 85%; // Editorial constraint
      letter-spacing: 0.002em; // Subtle positive tracking
    }

    .post-tags {
      display: flex;
      gap: $space-xs;
      margin-top: $space-sm;

      .tag {
        font-size: $font-size-xs;
        font-weight: $font-weight-medium;
        color: $text-tertiary;
        background: rgba(122, 132, 113, 0.08);
        padding: 0.2rem 0.6rem;
        border-radius: 8px;
        border: 1px solid rgba(122, 132, 113, 0.15);
        letter-spacing: 0.02em;
        transition: all var(--transition-fast);
      }
    }
  }
}

// Section footer styling
.section-footer {
  text-align: center;
  margin-top: $space-2xl;
  padding-top: $space-xl;
  border-top: 1px solid rgba(230, 228, 223, 0.3);
}

// Competency Areas - Sophisticated Professional Layout
.competency-areas {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: $space-2xl;
  margin-top: $space-2xl;

  @media (max-width: $breakpoint-md) {
    grid-template-columns: 1fr;
    gap: $space-xl;
    margin-top: $space-xl;
  }
}

.competency-group {
  position: relative;

  .competency-title {
    font-family: $font-primary;
    font-size: $font-size-lg;
    font-weight: $font-weight-medium;
    color: $text-primary;
    margin-bottom: $space-lg;
    letter-spacing: -0.02em;
    line-height: 1.3;
    position: relative;

    &::after {
      content: '';
      position: absolute;
      bottom: -0.5rem;
      left: 0;
      width: 2rem;
      height: 1px;
      background: $earth-coral;
      opacity: 0.4;
    }
  }
}

.competency-list {
  display: flex;
  flex-direction: column;
  gap: $space-sm;

  span {
    font-size: $font-size-base;
    font-weight: 400;
    color: $text-secondary;
    line-height: 1.5;
    letter-spacing: -0.01em;
    padding: $space-xs 0;
    border-bottom: 1px solid transparent;
    transition: all var(--transition-fast);

    &:hover {
      color: $text-primary;
      border-bottom-color: rgba(184, 118, 94, 0.2);
      padding-left: $space-xs;
    }
  }
}

// Section Header Minimal Variant
.section-header--minimal {
  text-align: left;
  margin-bottom: $space-xl;

  h2 {
    margin-bottom: $space-sm;
  }

  .section-subtitle {
    font-size: $font-size-base;
    color: $text-tertiary;
    font-weight: 400;
    letter-spacing: -0.01em;
    font-style: italic;
    margin: 0;
  }
}

// Technical Note - Sophisticated Callout
.technical-note {
  margin-top: $space-2xl;
  padding: $space-xl;
  background: linear-gradient(135deg, rgba(230, 228, 223, 0.3) 0%, rgba(230, 228, 223, 0.1) 100%);
  border-left: 3px solid $earth-coral;
  border-radius: 0 8px 8px 0;

  p {
    font-size: $font-size-base;
    color: $text-secondary;
    margin: 0;
    line-height: 1.6;
    letter-spacing: -0.01em;

    strong {
      color: $text-primary;
      font-weight: $font-weight-medium;
    }
  }

  @media (max-width: $breakpoint-sm) {
    padding: $space-lg;
    margin-top: $space-xl;
  }
}

// Highlight Link - Sophisticated External Links
.highlight-link {
  color: $earth-coral;
  text-decoration: none;
  border-bottom: 1px solid rgba(184, 118, 94, 0.3);
  font-weight: $font-weight-medium;
  transition: all var(--transition-fast);

  &:hover {
    color: $text-primary;
    border-bottom-color: $earth-coral;
    background: rgba(184, 118, 94, 0.05);
    padding: 0 0.2rem;
    margin: 0 -0.2rem;
    border-radius: 3px;
  }
}

// Accessibility Enhancements
// Focus management for keyboard navigation
*:focus {
  outline: 3px solid $earth-coral; // Enhanced 3px focus outline for better visibility
  outline-offset: 2px;
  border-radius: 2px;
}

// Skip to content link - already defined above, removing duplicate

// Enhanced button focus states
.btn:focus-visible {
  outline: 3px solid $earth-coral; // Consistent 3px outline
  outline-offset: 2px;
  box-shadow: 0 0 0 4px rgba(184, 118, 94, 0.2);
}

// Navigation accessibility
.nav-toggle:focus-visible {
  outline: 3px solid $earth-coral; // Consistent 3px outline
  outline-offset: 2px;
  background: rgba(184, 118, 94, 0.1);
}

.nav-links a:focus-visible {
  outline: 3px solid $earth-coral; // Consistent 3px outline
  outline-offset: 2px;
  background: rgba(184, 118, 94, 0.1);
}

// High contrast mode support
@media (prefers-contrast: high) {
  .work-item {
    border-bottom-color: $text-primary;
  }

  .skill-tag {
    border-width: 2px;
  }

  .nav-links a {
    border: 1px solid transparent;

    &:focus {
      border-color: $text-primary;
    }
  }
}

// Reduced motion preferences
@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .hero {
    transform: none !important;
  }

  .skill-tag:hover {
    transform: none !important;
  }

  .work-item:hover {
    transform: none !important;
  }
}

// Print styles for accessibility
@media print {
  .navigation,
  .skip-to-content,
  .btn {
    display: none;
  }

  body {
    font-size: 12pt;
    line-height: 1.4;
    color: black;
    background: white;
  }

  a {
    text-decoration: underline;
    color: black;
  }

  h1, h2, h3, h4, h5, h6 {
    page-break-after: avoid;
    font-weight: bold;
  }

  .section {
    page-break-inside: avoid;
  }
}

// About Page Typography Enhancements - Sophisticated Editorial Style
.about-section-title {
  font-size: clamp(2.4rem, 4vw, 3.6rem);
  margin-bottom: $space-2xl; // 3rem equivalent
  font-weight: $font-weight-light; // 300
}

.about-final-section {
  padding-bottom: $space-5xl; // 8rem equivalent but using design system
}

.about-cta-links {
  justify-content: center;
}

.section--about-typography {

  // Enhanced text hierarchy for About page
  .text-editorial {
    max-width: 68ch;
    margin: 0 auto;
    font-size: clamp(1.7rem, 2.4vw, 2rem);
    line-height: 1.65;
    letter-spacing: -0.012em;
    color: $text-secondary;
    font-weight: $font-weight-regular;

    p {
      margin-bottom: 2.8rem;
      font-feature-settings: "kern" 1, "liga" 1, "calt" 1;
