    color: $text-primary;
    margin-bottom: 3.5rem;
    text-align: center;
    letter-spacing: -0.035em;
    font-family: $font-primary;
    line-height: 1.1;

    @media (max-width: $breakpoint-md) {
      margin-bottom: 2.8rem;
    }

    @media (max-width: $breakpoint-sm) {
