.location-note {
  text-align: center;
  font-size: $font-size-base;
  color: $text-tertiary;
  font-style: italic;
  margin-top: $space-xl;

  strong {
    color: $earth-coral;
    font-weight: $font-weight-medium;
  }
}

// Hero Section Button Links
.hero-links {
  display: flex;
  gap: $space-lg;
  margin-top: $space-xl;
  flex-wrap: wrap;
  align-items: center;

  @media (max-width: $breakpoint-md) {
    flex-direction: column;
    align-items: stretch;
    gap: $space-md;
    width: 100%;
    max-width: 40rem; // Reasonable max width for buttons
    margin-left: auto;
    margin-right: auto;

    .btn {
      text-align: center;
      width: 100%;
      justify-content: center;
    }
  }

  // Optional animation class for staggered entrance
  &.animate {
    .btn {
      opacity: 0;
      transform: translateY(20px);
      animation: fadeInUp 0.8s ease-out forwards;

      &:first-child {
        animation-delay: 0.2s;
      }

      &:nth-child(2) {
        animation-delay: 0.4s;
      }
    }
  }
}

// Chat Bar Section - Sophisticated & Space-Efficient
.chat-bar-section {
  margin-top: $space-4xl;

  @media (max-width: $breakpoint-sm) {
    margin-top: $space-3xl;
  }
}

.chat-bar {
  background: linear-gradient(135deg, rgba(184, 118, 94, 0.04) 0%, rgba(255, 255, 255, 0.95) 100%);
  border: 1px solid rgba(184, 118, 94, 0.12);
  border-radius: 16px;
  padding: $space-2xl;
  backdrop-filter: blur(20px);
  position: relative;
  overflow: hidden;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);

  &:hover {
    background: linear-gradient(135deg, rgba(184, 118, 94, 0.06) 0%, rgba(255, 255, 255, 0.98) 100%);
    border-color: rgba(184, 118, 94, 0.18);
    box-shadow: 0 8px 32px rgba(184, 118, 94, 0.08);

    .cta-arrow {
      transform: translateX(4px);
    }
  }

  // Subtle animated background
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(184, 118, 94, 0.02), transparent);
    animation: shimmer 8s ease-in-out infinite;
    pointer-events: none;
  }

  @media (max-width: $breakpoint-md) {
    padding: $space-xl;
  }

  @media (max-width: $breakpoint-sm) {
    padding: $space-lg;
  }
}

@keyframes shimmer {
  0%, 100% { left: -100%; }
  50% { left: 100%; }
}

.chat-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: $space-2xl;
  margin-bottom: $space-lg;

  @media (max-width: $breakpoint-md) {
    flex-direction: column;
    align-items: flex-start;
    gap: $space-xl;
    text-align: left;
  }
}

.chat-text {
  flex: 1;

  h3 {
    font-size: clamp(1.8rem, 2.8vw, 2.4rem);
    font-weight: $font-weight-medium;
    color: $text-primary;
    margin: 0 0 $space-sm 0;
    line-height: 1.25;
    letter-spacing: -0.02em;
    font-feature-settings: "kern" 1, "liga" 1;
  }

  p {
    font-size: $font-size-base;
    color: $text-secondary;
    margin: 0;
    line-height: 1.4;
    letter-spacing: -0.005em;

    .location {
      color: $earth-coral;
      font-weight: $font-weight-medium;
      font-style: italic;
      opacity: 0.9;
    }
  }
}

.chat-actions {
  display: flex;
  align-items: center;
  gap: $space-lg;

  @media (max-width: $breakpoint-md) {
    width: 100%;
    justify-content: flex-start;
  }

  @media (max-width: $breakpoint-sm) {
    flex-direction: column;
    align-items: stretch;
    gap: $space-md;
  }
}

.cta-primary {
  display: flex;
  align-items: center;
  gap: $space-sm;
  padding: 1.2rem 2rem;
  background: $earth-coral;
  color: white;
  text-decoration: none;
  border-radius: 8px;
  font-size: $font-size-small;
  font-weight: $font-weight-semibold;
  letter-spacing: -0.01em;
  transition: all var(--transition-base);
  white-space: nowrap;

  &:hover {
    background: #a36952; // Manually darkened earth-coral
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(184, 118, 94, 0.3);
  }
}

.cta-secondary {
  padding: 1.2rem 2rem;
  color: $text-primary;
  text-decoration: none;
  border-radius: 8px;
  font-size: $font-size-small;
  font-weight: $font-weight-medium;
  letter-spacing: -0.01em;
  transition: all var(--transition-base);
  white-space: nowrap;
  position: relative;

  &::after {
    content: '';
    position: absolute;
    bottom: 8px;
    left: 50%;
    width: 0;
    height: 1px;
    background: $earth-coral;
    transition: all var(--transition-base);
    transform: translateX(-50%);
  }

  &:hover {
    color: $earth-coral;

    &::after {
      width: 70%;
    }
  }
}

.cta-arrow {
  font-size: 1.4rem;
  transition: transform 0.3s ease;
  font-weight: normal;
}

.chat-pulse {
  display: flex;
  align-items: center;
  gap: $space-sm;
  justify-content: center;
  opacity: 0.8;

  @media (max-width: $breakpoint-md) {
    justify-content: flex-start;
  }
}

.pulse-dot {
  width: 8px;
  height: 8px;
  background: #22c55e;
  border-radius: 50%;
  animation: pulse-status 2s ease-in-out infinite;
  position: relative;

  &::before {
    content: '';
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    background: #22c55e;
    border-radius: 50%;
    opacity: 0.3;
    animation: pulse-ring 2s ease-in-out infinite;
  }
}

@keyframes pulse-status {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.6; }
}

@keyframes pulse-ring {
  0%, 100% { 
    transform: scale(1);
    opacity: 0.3; 
  }
  50% { 
    transform: scale(1.5);
    opacity: 0; 
  }
}

.pulse-text {
  font-size: $font-size-xs;
  color: $text-tertiary;
  font-weight: $font-weight-medium;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}


// Site footer styling
footer {
  padding: 2rem 0; // Design system desktop spacing (32px)
  background: #fefcfa;
  border-top: 1px solid rgba(230, 228, 223, 0.2);
  margin-top: 2rem; // Reduced margin for ultra-tight aesthetic

  @media (max-width: $breakpoint-sm) {
    padding: 1.5rem 0; // Design system mobile spacing (24px)
    margin-top: 1.5rem; // Consistent with mobile spacing
  }

  small {
    display: block;
    text-align: center;

    > div {
      display: flex;
      justify-content: center;
      gap: 2rem;
      align-items: center;

      @media (max-width: 48rem) {
        gap: 1.5rem;
      }
    }

    a {
      opacity: 0.7;
      transition: opacity 0.2s ease;

      &:hover {
        opacity: 1;
      }
    }
  }
}


// Hero reveal animation keyframes
@keyframes heroReveal {
  0% {
    opacity: 0;
    transform: translateY(30px) scale(0.98);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}


// Underline grow animation for emphasized text
@keyframes underlineGrow {
  0% {
    transform: scaleX(0);
    opacity: 0;
  }
  100% {
    transform: scaleX(1);
    opacity: 0.4;
  }
}

// Subtle hover effects for interactive elements
.hero-links {
  .btn {
    transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);

    &:hover {
      transform: translateY(-2px);
      box-shadow: 0 8px 25px rgba(0, 0, 0, 0.1);
    }

    &:active {
      transform: translateY(0);
    }
  }
}

