// Modern Design System Implementation
// Clean • Technical • Sophisticated • Minimal • Professional
@use "variables" as *;

// CSS Custom Properties Setup
:root {
  // Colors - Earthy Sophisticated with Friendly Touch
  --color-primary: #{$earth-coral};
  --color-text: #{$earth-text-primary};
  --color-text-secondary: #{$earth-text-secondary};
  --color-text-muted: #{$earth-text-tertiary};
  --color-background: #{$earth-background};
  --color-background-subtle: #{$earth-background-subtle};
  --color-surface: #{$earth-surface};
  --color-accent: #{$accent-primary};

  // Typography
  --font-primary: #{$font-primary};
  --font-secondary: #{$font-secondary};
  --font-mono: #{$font-mono};

  // Spacing
  --space-xs: #{$space-xs};
  --space-sm: #{$space-sm};
  --space-md: #{$space-md};
  --space-lg: #{$space-lg};
  --space-xl: #{$space-xl};
  --space-2xl: #{$space-2xl};
  --space-3xl: #{$space-3xl};
  --space-4xl: #{$space-4xl};
  --space-5xl: #{$space-5xl};

  // Shadows
  --shadow-sm: 0 0.4rem 2rem rgba(28, 28, 28, 0.04);
  --shadow-md: 0 0.8rem 3rem rgba(28, 28, 28, 0.08);
  --shadow-lg: 0 1.6rem 4rem rgba(28, 28, 28, 0.12);

  // Border Radius
  --radius-sm: 0.4rem;
  --radius-md: 0.8rem;
  --radius-lg: 1.6rem;
  --radius-full: 50%;

  // Transitions - Standardized boring.industries timing
  --transition-fast: 0.15s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --transition-base: 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --transition-slow: 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);

  // Animation timing for consistency
  --easing-standard: cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --easing-dramatic: cubic-bezier(0.16, 1, 0.3, 1);
  --easing-gentle: ease-out;
}

// Sophisticated Typography System
.hero-title {
  font-size: clamp(5.4rem, 12vw, 16rem); // Increased size for impact
  font-weight: $font-weight-medium; // Consistent with h1 hierarchy (450)
  line-height: 0.88; // Tighter for drama
  letter-spacing: -0.06em; // More aggressive kerning
  color: $text-primary;
  font-family: $font-display;
  font-feature-settings: "kern" 1, "liga" 1;
  text-rendering: optimizeLegibility;
  margin: $space-sm 0 $space-lg 0;
  text-shadow: 0 2px 30px rgba(0, 0, 0, 0.03);

  @media (prefers-reduced-motion: no-preference) {
    animation: heroReveal 1.5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    transform: translateY(30px) scale(0.95);
    opacity: 0;
    animation-delay: 0.2s;
  }

  // Waving hand animation
  .wave-emoji {
    display: inline-block;
    animation: wave 2.5s ease-in-out infinite;
    animation-delay: 1s;
    transform-origin: 70% 70%;
    cursor: pointer;

    &:hover {
      animation-duration: 0.6s;
      animation-iteration-count: 3;
    }
  }
}

// Hero greeting - Small, subtle introduction
.hero-greeting {
  font-size: clamp(1.6rem, 2.5vw, 2rem);
  font-weight: 500;
  color: $earth-coral;
  letter-spacing: -0.01em;
  margin-bottom: $space-md;
  font-family: $font-primary;
  text-transform: uppercase;
  font-size: clamp(1.2rem, 2vw, 1.4rem);
  letter-spacing: 0.1em;

  @media (prefers-reduced-motion: no-preference) {
    animation: heroReveal 1.2s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    transform: translateY(20px);
    opacity: 0;
    animation-delay: 0s;
  }
}

// Hero subtitle - Compelling, concise value proposition
.hero-subtitle {
  font-size: clamp(2rem, 3.5vw, 2.8rem);
  font-weight: 400;
  color: $text-secondary;
  line-height: 1.3;
  letter-spacing: -0.03em;
  margin: $space-2xl 0 $space-4xl 0;
  padding: 0;
  max-width: 50ch;
  font-family: $font-primary;
  position: relative;

  // Add horizontal padding on tablet and mobile when layout is stacked
  @media (max-width: $breakpoint-md) {
    padding: 0 $space-lg;
  }

  @media (prefers-reduced-motion: no-preference) {
    animation: heroReveal 1.3s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    transform: translateY(25px);
    opacity: 0;
    animation-delay: 0.4s;
  }

  // Subtle underline decoration for emphasized text
  strong {
    position: relative;

    &::after {
      content: '';
      position: absolute;
      bottom: -2px;
      left: 0;
      width: 100%;
      height: 2px;
      background: linear-gradient(90deg, $earth-coral, transparent);
      opacity: 0.4;
      transform: scaleX(0);
      animation: underlineGrow 1s cubic-bezier(0.16, 1, 0.3, 1) forwards;
      animation-delay: 1.2s;
      transform-origin: left;
    }
  }

  p {
    margin: 0;
  }

  strong {
    color: $text-primary;
    font-weight: 500;
  }
}

// Clean Animation System
@keyframes wave {
  0%, 100% { 
    transform: rotate(0deg); 
  }
  10%, 30% { 
    transform: rotate(14deg); 
  }
  20% { 
    transform: rotate(-8deg); 
  }
  40%, 60% { 
    transform: rotate(14deg); 
  }
  50% { 
    transform: rotate(-8deg); 
  }
  70%, 90% { 
    transform: rotate(0deg); 
  }
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes subtleSlideUp {
  from {
    opacity: 0;
    transform: translateY(15px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes navFadeIn {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

