    font-size: clamp(2.8rem, 5vw, 4.8rem); // More restrained, boring.industries style
  }

  h2 {
    margin-bottom: $space-md; // Much tighter spacing
    font-weight: $font-weight-regular; // Consistent hierarchy (400)
    letter-spacing: -0.04em; // Tighter kerning like boring.industries
