// Grid System
.grid {
  display: grid;
  gap: $space-xl;

  &--2-cols {
    grid-template-columns: repeat(2, 1fr);

    @media (max-width: $breakpoint-md) {
      grid-template-columns: 1fr;
    }
  }

  &--3-cols {
    grid-template-columns: repeat(3, 1fr);

    @media (max-width: $breakpoint-lg) {
      grid-template-columns: repeat(2, 1fr);
    }

    @media (max-width: $breakpoint-sm) {
      grid-template-columns: 1fr;
    }
  }
}

// Container System with Mobile Support
.container {
  max-width: $container-standard;
  margin: 0 auto;
  padding: 0 $space-xl;

  @media (max-width: $breakpoint-md) {
    padding: 0 $space-lg;
  }

  @media (max-width: $breakpoint-sm) {
    padding: 0 $space-md; // Better mobile padding - 16px for readability
  }

  &--narrow {
    max-width: $container-narrow;
  }

  &--wide {
    max-width: $container-wide;
  }

  &--full {
    max-width: $container-full;
  }
}

// Animation Classes
.fade-in {
  opacity: 0;
  transform: translateY(2rem);
  transition: all var(--transition-slow);

  &.visible {
    opacity: 1;
    transform: translateY(0);
  }
}

.stagger-item {
  opacity: 1; // Make visible by default
  transform: translateY(0); // No transform by default
  transition: all 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);

  // Only apply initial hidden state if JavaScript is available and page is loaded
  &.animate-on-load {
    opacity: 0;
    transform: translateY(2rem);

    &:nth-child(1) {
      transition-delay: 0.1s;
    }
    &:nth-child(2) {
      transition-delay: 0.2s;
    }
    &:nth-child(3) {
      transition-delay: 0.3s;
    }
    &:nth-child(4) {
      transition-delay: 0.4s;
    }
  }

  &.visible {
    opacity: 1;
    transform: translateY(0);
  }
}

// Minimal Form Elements - Aligned with Design System
.form-group {
  margin-bottom: $space-lg;

  label {
    display: block;
    font-size: $font-size-small;
    font-weight: $font-weight-medium;
    color: $text-primary;
    margin-bottom: $space-sm;
    letter-spacing: -0.01em; // Consistent with design system
    font-family: $font-primary;
  }

  input,
  textarea {
    width: 100%;
    padding: 1.6rem 2rem; // More generous, sophisticated padding
    border: 1px solid rgba(0, 0, 0, 0.1); // Minimal border
    border-radius: 8px; // Consistent with buttons
    font-size: $font-size-base;
    font-family: $font-primary;
    background: rgba(255, 255, 255, 0.9);
    transition: all var(--transition-base);
    letter-spacing: -0.005em; // Consistent typography

    &:focus {
      outline: none;
      border-color: $earth-coral;
      box-shadow: 0 0 0 3px rgba(184, 118, 94, 0.1);
      background: rgba(255, 255, 255, 1);
      transform: translateY(-1px); // Subtle lift on focus
    }

    &:hover:not(:focus) {
      border-color: rgba(184, 118, 94, 0.2);
      background: rgba(255, 255, 255, 0.95);
    }

    &::placeholder {
      color: $text-quaternary;
      font-style: italic;
    }
  }

  textarea {
    min-height: 12rem;
    resize: vertical;
    line-height: 1.5; // Consistent with body text
  }
}

// Utility Classes
.text-center {
  text-align: center;
}
.text-left {
  text-align: left;
}
.text-right {
  text-align: right;
}

.mb-0 {
  margin-bottom: 0;
}
.mb-sm {
  margin-bottom: var(--space-sm);
}
.mb-md {
  margin-bottom: var(--space-md);
}
.mb-lg {
  margin-bottom: var(--space-lg);
}
.mb-xl {
  margin-bottom: var(--space-xl);
}
.mb-2xl {
  margin-bottom: var(--space-2xl);
}
.mb-3xl {
  margin-bottom: var(--space-3xl);
}

.mt-0 {
  margin-top: 0;
}
.mt-sm {
  margin-top: var(--space-sm);
}
.mt-md {
  margin-top: var(--space-md);
}
.mt-lg {
  margin-top: var(--space-lg);
}
.mt-xl {
  margin-top: var(--space-xl);
}
.mt-2xl {
  margin-top: var(--space-2xl);
}
.mt-3xl {
  margin-top: var(--space-3xl);
}

// Accessibility
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

// Skip to content link for keyboard navigation
.skip-to-content {
  position: fixed;
  top: -100px;
  left: 1rem;
  z-index: 10000;
  padding: 1rem 1.5rem;
  background: $earth-coral;
  color: white;
  font-weight: $font-weight-medium;
  text-decoration: none;
  border-radius: 0 0 0.5rem 0.5rem;
  transition: top 0.3s ease;
  font-size: 1.4rem;

  &:focus {
    top: 0;
    outline: 3px solid #fff;
    outline-offset: 2px;
  }

  &:hover {
    background: #a36952;
    color: white;
    text-decoration: none;
  }
}

// Focus indicators
*:focus {
  outline: 2px solid $clay-orange;
  outline-offset: 2px;
}

// Reduced motion support
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

// Ultra Minimal Work Cards - Boring Industries Style
.work-grid {
  display: flex;
  flex-direction: column;
  gap: 0;
  margin-top: $space-xl;

  .work-item {
    display: block;
    padding: $space-xl 0;
    background: transparent;
    border: none;
    border-bottom: 1px solid rgba(0, 0, 0, 0.05);
    text-decoration: none;
    transition: all var(--transition-base);
    position: relative;

    @media (max-width: $breakpoint-md) {
      padding: $space-lg 0;
    }

    @media (max-width: $breakpoint-sm) {
      padding: $space-md 0;
    }

    &:first-child {
      padding-top: 0;
    }

    &:last-child {
      border-bottom: none;
      padding-bottom: 0;
    }

    &:hover {
      background: rgba(184, 118, 94, 0.02);
      border-bottom-color: rgba(184, 118, 94, 0.3);
      padding-left: $space-md;
      padding-right: $space-md;
      margin-left: -$space-md;
      margin-right: -$space-md;
      border-radius: 8px;

      .work-title {
        color: $earth-coral;
        text-decoration: underline;
        text-decoration-thickness: 1px;
        text-underline-offset: 4px;
      }

      .work-year {
        color: $earth-coral;
        opacity: 1;
        transform: scale(1.05);
      }
    }

    .work-content {
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      gap: $space-lg;

      @media (max-width: $breakpoint-sm) {
        flex-direction: column;
        gap: $space-sm;
      }

      .work-info {
        flex: 1;
        min-width: 0; // Allow flexbox shrinking

        .work-title {
          font-size: $font-size-large;
          font-weight: $font-weight-medium;
          color: $text-primary;
          margin: 0 0 $space-xs 0;
          line-height: 1.3;
          transition: all var(--transition-base);
          font-family: $font-primary;
          letter-spacing: -0.02em;

          @media (max-width: $breakpoint-sm) {
            font-size: $font-size-base;
          }
        }

        .work-description {
          font-size: $font-size-base;
          color: $text-secondary;
          line-height: 1.4;
          margin: 0;
          font-weight: $font-weight-regular;
          letter-spacing: -0.01em;

          @media (max-width: $breakpoint-sm) {
            font-size: $font-size-small;
            max-width: 100%;
          }
        }
      }
    }

    .work-year {
      font-size: $font-size-xs;
      color: $text-quaternary;
      font-weight: $font-weight-medium;
      text-transform: uppercase;
      letter-spacing: 0.12em;
      white-space: nowrap;
      flex-shrink: 0;
      opacity: 0.8;
      transition: all var(--transition-base);

      @media (max-width: $breakpoint-sm) {
        align-self: flex-start;
        font-size: $font-size-xs;
        margin-top: $space-xs;
      }
    }
  }

  // Enhanced work item variants with visual indicators
  .work-indicator {
    display: flex;
    align-items: center;
    gap: $space-sm;
    margin-bottom: $space-sm;

    .work-icon {
      font-size: 1.8rem;
      opacity: 0.8;
      transition: all var(--transition-base);
    }

    .work-status {
      font-size: $font-size-xs;
      font-weight: $font-weight-medium;
      text-transform: uppercase;
      letter-spacing: 0.1em;
      padding: 0.2rem 0.6rem;
      border-radius: 12px;
      background: rgba(184, 118, 94, 0.1);
      color: $earth-coral;
      border: 1px solid rgba(184, 118, 94, 0.2);
    }
  }

  .work-tags {
    display: flex;
    gap: $space-xs;
    margin-top: $space-sm;
    flex-wrap: wrap;

    .tag {
      font-size: $font-size-xs;
      font-weight: $font-weight-medium;
      color: $text-tertiary;
      background: rgba(122, 132, 113, 0.08);
      padding: 0.2rem 0.6rem;
      border-radius: 8px;
      border: 1px solid rgba(122, 132, 113, 0.15);
      letter-spacing: 0.02em;
      transition: all var(--transition-fast);
    }
  }

  // Work item type variants
  &.work-item--external {
    .work-status {
      background: rgba(45, 90, 69, 0.1);
      color: #2d5a45;
      border-color: rgba(45, 90, 69, 0.2);
    }
  }

  &.work-item--consulting {
    .work-status {
      background: rgba(184, 118, 94, 0.1);
      color: $earth-coral;
      border-color: rgba(184, 118, 94, 0.2);
    }
  }

  &.work-item--enterprise {
    .work-status {
      background: rgba(155, 144, 136, 0.1);
      color: $earth-stone;
      border-color: rgba(155, 144, 136, 0.2);
    }
  }

  &.work-item--creative {
    .work-status {
      background: rgba(107, 119, 99, 0.1);
      color: $earth-moss;
      border-color: rgba(107, 119, 99, 0.2);
    }
  }

  &:hover {
    .work-indicator .work-icon {
      opacity: 1;
      transform: scale(1.1);
    }

    .work-tags .tag {
      background: rgba(122, 132, 113, 0.12);
      border-color: rgba(122, 132, 113, 0.25);
      color: $text-secondary;
    }
  }
}

// Compact Work Cards - Modern Card Layout
.work-grid--compact {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: $space-xl;
  margin-top: $space-xl;

  @media (min-width: $breakpoint-lg) {
    grid-template-columns: repeat(3, 1fr); // Force 3 columns on desktop
    gap: $space-2xl; // More spacing for luxurious look
  }

  @media (max-width: $breakpoint-md) {
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: $space-md;
  }

  @media (max-width: $breakpoint-sm) {
    grid-template-columns: 1fr;
    gap: $space-md;
  }
}

.work-card {
  position: relative;
  background: $background-primary;
  border: 1px solid $border-light;
  border-radius: 8px;
  padding: $space-md; // Tighter spacing for boring.industries aesthetic (16px)
  transition: all var(--transition-base);
  overflow: hidden;

  &:hover {
    border-color: $border-medium;
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.08);

    .work-card-link::after {
      opacity: 1;
    }
  }

  .work-card-header {
    display: flex;
    justify-content: flex-end;
    margin-bottom: $space-md;
  }

  .work-card-content {
    position: relative;
    z-index: 2;
  }

  .work-card-icon {
    font-size: 3rem;
    margin-bottom: $space-md;
    display: block;
    opacity: 0.8;
  }

  .work-card-title {
    font-family: $font-primary;
    font-size: clamp(1.8rem, 2.5vw, 2.2rem); // Fluid typography like boring.industries
    font-weight: 450; // Consistent lighter weight
    color: $text-primary;
    margin-bottom: $space-sm;
    line-height: 1.25; // Tighter line height
    letter-spacing: -0.025em; // Tighter kerning for sophistication
  }

  .work-card-description {
    font-size: clamp(1.4rem, 1.8vw, 1.6rem); // Fluid scaling
    color: $text-secondary;
    line-height: 1.3; // Ultra-tight line height for boring.industries aesthetic
    margin-bottom: $space-lg;
    letter-spacing: -0.015em; // Refined kerning
    font-weight: 400;
  }

  .work-card-meta {
    display: flex;
    justify-content: space-between;
    align-items: center;

    .work-type {
      font-size: $font-size-xs;
      color: $text-tertiary;
      font-weight: $font-weight-medium;
      text-transform: uppercase;
      letter-spacing: 0.1em;
    }

    .work-year {
      font-size: $font-size-xs;
      color: $text-quaternary;
      font-weight: $font-weight-medium;
    }
  }

  .work-card-link {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: 3;

    &::after {
      content: '';
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: linear-gradient(135deg, rgba(184, 118, 94, 0.02) 0%, rgba(184, 118, 94, 0.04) 100%);
      opacity: 0;
      transition: opacity 0.3s ease;
    }
  }
}

.work-status {
  font-size: $font-size-xs;
  font-weight: $font-weight-medium;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  padding: 0.3rem 0.8rem;
  border-radius: 12px;

  &--active {
    background: rgba(76, 175, 80, 0.1);
    color: #4CAF50;
  }

  &--live {
    background: rgba(184, 118, 94, 0.1);
    color: $earth-coral;
  }

  &--delivered {
    background: rgba(122, 132, 113, 0.1);
    color: $earth-sage;
  }

  &--published {
    background: rgba(107, 119, 99, 0.1);
    color: $earth-moss;
    border-color: rgba(107, 119, 99, 0.2);
  }
}

// About Page Content Grids - Clean & Organized
.expertise-grid,
.philosophy-grid,
.deliverables-grid,
.personal-grid {
  display: grid;
  gap: $space-lg;
  margin-top: $space-xl;

  @media (max-width: $breakpoint-sm) {
    grid-template-columns: 1fr;
    gap: $space-md;
  }
}

.expertise-grid {
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
}

.philosophy-grid,
.deliverables-grid {
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
}

.personal-grid {
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
}

.expertise-item,
.philosophy-item,
.deliverable-item,
.personal-item {
  background: linear-gradient(135deg, rgba(184, 118, 94, 0.03) 0%, rgba(255, 255, 255, 0.8) 100%);
  border: 1px solid rgba(184, 118, 94, 0.08);
  border-radius: 12px;
  padding: 3rem; // More generous padding for better whitespace
  position: relative;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  backdrop-filter: blur(10px);
  margin-bottom: $space-lg; // Better spacing between items
  display: flex;
  align-items: flex-start;
  gap: $space-lg; // Space between icon and content

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 4px;
    height: 100%;
    background: linear-gradient(180deg, $earth-coral 0%, rgba(184, 118, 94, 0.3) 100%);
    border-radius: 2px 0 0 2px;
  }

  strong {
    font-weight: $font-weight-semibold;
    color: $text-primary;
    letter-spacing: -0.015em;
    display: block;
    margin-bottom: $space-xs;
  }

  &:hover {
    transform: translateY(-4px);
    box-shadow: 0 8px 32px rgba(184, 118, 94, 0.12);
    border-color: rgba(184, 118, 94, 0.15);
    background: linear-gradient(135deg, rgba(184, 118, 94, 0.05) 0%, rgba(255, 255, 255, 0.9) 100%);
  }
