.personal-item {
  background: linear-gradient(135deg, rgba(122, 132, 113, 0.03) 0%, rgba(255, 255, 255, 0.8) 100%);
  border-color: rgba(122, 132, 113, 0.08);

  &::before {
    background: linear-gradient(180deg, $earth-sage 0%, rgba(122, 132, 113, 0.3) 100%);
  }

  &:hover {
    background: linear-gradient(135deg, rgba(122, 132, 113, 0.05) 0%, rgba(255, 255, 255, 0.9) 100%);
    border-color: rgba(122, 132, 113, 0.15);
    box-shadow: 0 8px 32px rgba(122, 132, 113, 0.12);
  }
}

// Fine Art Editorial Blog Posts - Gallery Aesthetic
.post-grid {
