// Highlight Link - Sophisticated External Links
.highlight-link {
  color: $earth-coral;
  text-decoration: none;
  border-bottom: 1px solid rgba(184, 118, 94, 0.3);
  font-weight: $font-weight-medium;
  transition: all var(--transition-fast);

  &:hover {
    color: $text-primary;
    border-bottom-color: $earth-coral;
    background: rgba(184, 118, 94, 0.05);
    padding: 0 0.2rem;
    margin: 0 -0.2rem;
    border-radius: 3px;
  }
}

// Accessibility Enhancements
// Focus management for keyboard navigation
*:focus {
  outline: 3px solid $earth-coral; // Enhanced 3px focus outline for better visibility
  outline-offset: 2px;
  border-radius: 2px;
}

// Skip to content link - already defined above, removing duplicate

// Enhanced button focus states
.btn:focus-visible {
  outline: 3px solid $earth-coral; // Consistent 3px outline
  outline-offset: 2px;
  box-shadow: 0 0 0 4px rgba(184, 118, 94, 0.2);
}

// Navigation accessibility
.nav-toggle:focus-visible {
  outline: 3px solid $earth-coral; // Consistent 3px outline
  outline-offset: 2px;
  background: rgba(184, 118, 94, 0.1);
}

.nav-links a:focus-visible {
  outline: 3px solid $earth-coral; // Consistent 3px outline
  outline-offset: 2px;
  background: rgba(184, 118, 94, 0.1);
}

// High contrast mode support
@media (prefers-contrast: high) {
  .work-item {
    border-bottom-color: $text-primary;
  }

  .skill-tag {
    border-width: 2px;
  }

  .nav-links a {
    border: 1px solid transparent;

    &:focus {
      border-color: $text-primary;
    }
  }
}

// Reduced motion preferences
@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .hero {
    transform: none !important;
  }

  .skill-tag:hover {
    transform: none !important;
  }

  .work-item:hover {
    transform: none !important;
  }
}

// Print styles for accessibility
@media print {
  .navigation,
  .skip-to-content,
  .btn {
    display: none;
  }

  body {
    font-size: 12pt;
    line-height: 1.4;
    color: black;
    background: white;
  }

  a {
    text-decoration: underline;
    color: black;
  }

  h1, h2, h3, h4, h5, h6 {
    page-break-after: avoid;
    font-weight: bold;
  }

  .section {
    page-break-inside: avoid;
  }
}

// About Page Typography Enhancements - Sophisticated Editorial Style
.about-section-title {
  font-size: clamp(2.4rem, 4vw, 3.6rem);
  margin-bottom: $space-2xl; // 3rem equivalent
  font-weight: $font-weight-light; // 300
}

.about-final-section {
  padding-bottom: $space-5xl; // 8rem equivalent but using design system
}

.about-cta-links {
  justify-content: center;
}

.section--about-typography {

  // Enhanced text hierarchy for About page
  .text-editorial {
    max-width: 68ch;
    margin: 0 auto;
    font-size: clamp(1.7rem, 2.4vw, 2rem);
    line-height: 1.65;
    letter-spacing: -0.012em;
    color: $text-secondary;
    font-weight: $font-weight-regular;

    p {
      margin-bottom: 2.8rem;
      font-feature-settings: "kern" 1, "liga" 1, "calt" 1;
      text-rendering: optimizeLegibility;

      @media (max-width: $breakpoint-sm) {
        margin-bottom: 2.2rem;
        font-size: clamp(1.5rem, 3vw, 1.7rem);
      }
    }

    a {
      color: $earth-coral;
      text-decoration: none;
      border-bottom: 1px solid rgba(217, 101, 74, 0.3);
      transition: all var(--transition-base);

      &:hover {
        color: rgba(195, 91, 66, 1);
        border-bottom-color: $earth-coral;
      }
    }
  }

  // Refined section headings
  .section-title-refined {
    font-size: clamp(2.6rem, 4.5vw, 3.8rem);
    font-weight: 300;
    color: $text-primary;
    margin-bottom: 3.5rem;
    text-align: center;
    letter-spacing: -0.035em;
    font-family: $font-primary;
    line-height: 1.1;

    @media (max-width: $breakpoint-md) {
      margin-bottom: 2.8rem;
    }

    @media (max-width: $breakpoint-sm) {
      font-size: clamp(2.2rem, 6vw, 2.6rem);
      margin-bottom: 2.2rem;
    }
  }
}

// About page specific responsive adjustments
body[data-page="about"] {

  .section--editorial {
    padding: $space-xl 0; // Design system desktop spacing (32px)

    @media (max-width: $breakpoint-md) {
      padding: $space-lg 0; // Tablet spacing (24px)
    }

    @media (max-width: $breakpoint-sm) {
      padding: $space-md 0; // Mobile spacing (16px)
    }
  }

  // Ensure proper text flow and readability
  .hero-subtitle p {
    font-size: clamp(1.9rem, 3.2vw, 2.6rem);
    line-height: 1.4;
    letter-spacing: -0.02em;
    max-width: 52ch;

    @media (max-width: $breakpoint-sm) {
      max-width: none;
    }
  }
}

// Expertise Item Icon Styling
.expertise-icon {
  font-size: 2.4rem; // Large enough to be impactful
  min-width: 3.2rem; // Consistent width
  height: 3.2rem;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, rgba(184, 118, 94, 0.1) 0%, rgba(255, 255, 255, 0.8) 100%);
  border-radius: 8px;
  border: 1px solid rgba(184, 118, 94, 0.15);
  backdrop-filter: blur(10px);
  transition: all var(--transition-base);
  margin-top: 0.2rem; // Slight alignment adjustment
}

.expertise-content {
  flex: 1; // Take remaining space
  font-size: $font-size-base;
  line-height: 1.5;
  letter-spacing: -0.01em;

  strong {
    display: block;
    margin-bottom: 0.8rem;
    font-size: 1.7rem;
    font-weight: $font-weight-semibold;
    color: $text-primary;
    letter-spacing: -0.02em;
  }
}

// Enhanced hover effects for expertise items
.expertise-item:hover {
  .expertise-icon {
    background: linear-gradient(135deg, rgba(184, 118, 94, 0.2) 0%, rgba(255, 255, 255, 0.9) 100%);
    border-color: rgba(184, 118, 94, 0.3);
    transform: translateY(-2px);
  }
}

// Contact Page Service Grid
.service-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: $space-lg;
  margin: $space-2xl 0;

  @media (max-width: $breakpoint-sm) {
    grid-template-columns: 1fr;
    gap: $space-md;
    margin: $space-xl 0;
  }
}

.service-item {
  display: flex;
  align-items: flex-start;
  gap: $space-md;
  padding: $space-lg;
  background: linear-gradient(135deg, rgba(184, 118, 94, 0.02) 0%, rgba(255, 255, 255, 0.7) 100%);
  border: 1px solid rgba(184, 118, 94, 0.06);
  border-radius: 10px;
  transition: all var(--transition-base);
  backdrop-filter: blur(5px);

  &:hover {
    background: linear-gradient(135deg, rgba(184, 118, 94, 0.05) 0%, rgba(255, 255, 255, 0.9) 100%);
    border-color: rgba(184, 118, 94, 0.12);
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(184, 118, 94, 0.08);
  }
}

.service-icon {
  font-size: 2rem;
  min-width: 2.8rem;
  height: 2.8rem;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, rgba(184, 118, 94, 0.08) 0%, rgba(255, 255, 255, 0.8) 100%);
  border-radius: 6px;
  border: 1px solid rgba(184, 118, 94, 0.1);
  transition: all var(--transition-base);
}

.service-content {
  flex: 1;

  strong {
    display: block;
    font-size: 1.5rem;
    font-weight: $font-weight-semibold;
    color: $text-primary;
    margin-bottom: 0.4rem;
    letter-spacing: -0.01em;
  }

  span {
    display: block;
    font-size: $font-size-small;
    color: $text-tertiary;
    line-height: 1.4;
    letter-spacing: 0.002em;
  }
}

// Contact intro and location styling
.contact-intro {
  text-align: center;

  > p:first-child {
    font-size: clamp(1.7rem, 2.2vw, 2rem);
    line-height: 1.4;
    color: $text-secondary;
    margin-bottom: $space-xl;
    max-width: 50rem;
    margin-left: auto;
    margin-right: auto;
  }
}

.location-note {
  text-align: center;
  font-size: $font-size-base;
  color: $text-tertiary;
  font-style: italic;
  margin-top: $space-xl;

  strong {
    color: $earth-coral;
    font-weight: $font-weight-medium;
  }
}

// Hero Section Button Links
.hero-links {
  display: flex;
  gap: $space-lg;
  margin-top: $space-xl;
  flex-wrap: wrap;
  align-items: center;

  @media (max-width: $breakpoint-md) {
    flex-direction: column;
    align-items: stretch;
    gap: $space-md;
    width: 100%;
    max-width: 40rem; // Reasonable max width for buttons
    margin-left: auto;
    margin-right: auto;

    .btn {
      text-align: center;
      width: 100%;
      justify-content: center;
    }
  }

  // Optional animation class for staggered entrance
  &.animate {
    .btn {
      opacity: 0;
      transform: translateY(20px);
      animation: fadeInUp 0.8s ease-out forwards;

      &:first-child {
        animation-delay: 0.2s;
      }

      &:nth-child(2) {
        animation-delay: 0.4s;
      }
    }
  }
}

// Chat Bar Section - Sophisticated & Space-Efficient
.chat-bar-section {
  margin-top: $space-4xl;

  @media (max-width: $breakpoint-sm) {
    margin-top: $space-3xl;
  }
}

.chat-bar {
  background: linear-gradient(135deg, rgba(184, 118, 94, 0.04) 0%, rgba(255, 255, 255, 0.95) 100%);
  border: 1px solid rgba(184, 118, 94, 0.12);
  border-radius: 16px;
  padding: $space-2xl;
  backdrop-filter: blur(20px);
  position: relative;
  overflow: hidden;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94);

  &:hover {
    background: linear-gradient(135deg, rgba(184, 118, 94, 0.06) 0%, rgba(255, 255, 255, 0.98) 100%);
    border-color: rgba(184, 118, 94, 0.18);
    box-shadow: 0 8px 32px rgba(184, 118, 94, 0.08);

    .cta-arrow {
      transform: translateX(4px);
    }
  }

  // Subtle animated background
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(184, 118, 94, 0.02), transparent);
    animation: shimmer 8s ease-in-out infinite;
    pointer-events: none;
  }

  @media (max-width: $breakpoint-md) {
    padding: $space-xl;
  }

  @media (max-width: $breakpoint-sm) {
    padding: $space-lg;
  }
}

@keyframes shimmer {
  0%, 100% { left: -100%; }
  50% { left: 100%; }
}

.chat-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: $space-2xl;
  margin-bottom: $space-lg;

  @media (max-width: $breakpoint-md) {
    flex-direction: column;
    align-items: flex-start;
    gap: $space-xl;
    text-align: left;
  }
}

.chat-text {
  flex: 1;

  h3 {
    font-size: clamp(1.8rem, 2.8vw, 2.4rem);
    font-weight: $font-weight-medium;
    color: $text-primary;
    margin: 0 0 $space-sm 0;
    line-height: 1.25;
    letter-spacing: -0.02em;
    font-feature-settings: "kern" 1, "liga" 1;
  }

  p {
    font-size: $font-size-base;
    color: $text-secondary;
    margin: 0;
    line-height: 1.4;
    letter-spacing: -0.005em;

    .location {
      color: $earth-coral;
      font-weight: $font-weight-medium;
      font-style: italic;
      opacity: 0.9;
    }
  }
}

.chat-actions {
  display: flex;
  align-items: center;
  gap: $space-lg;

  @media (max-width: $breakpoint-md) {
    width: 100%;
    justify-content: flex-start;
  }

  @media (max-width: $breakpoint-sm) {
    flex-direction: column;
    align-items: stretch;
    gap: $space-md;
  }
}

.cta-primary {
  display: flex;
  align-items: center;
  gap: $space-sm;
  padding: 1.2rem 2rem;
  background: $earth-coral;
  color: white;
  text-decoration: none;
  border-radius: 8px;
  font-size: $font-size-small;
  font-weight: $font-weight-semibold;
  letter-spacing: -0.01em;
  transition: all var(--transition-base);
  white-space: nowrap;

  &:hover {
    background: #a36952; // Manually darkened earth-coral
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(184, 118, 94, 0.3);
  }
}

.cta-secondary {
  padding: 1.2rem 2rem;
  color: $text-primary;
  text-decoration: none;
  border-radius: 8px;
  font-size: $font-size-small;
  font-weight: $font-weight-medium;
  letter-spacing: -0.01em;
  transition: all var(--transition-base);
  white-space: nowrap;
  position: relative;

  &::after {
    content: '';
    position: absolute;
    bottom: 8px;
    left: 50%;
    width: 0;
    height: 1px;
    background: $earth-coral;
    transition: all var(--transition-base);
    transform: translateX(-50%);
  }

  &:hover {
    color: $earth-coral;

    &::after {
      width: 70%;
    }
  }
}

.cta-arrow {
  font-size: 1.4rem;
  transition: transform 0.3s ease;
  font-weight: normal;
}

.chat-pulse {
  display: flex;
  align-items: center;
  gap: $space-sm;
  justify-content: center;
  opacity: 0.8;

  @media (max-width: $breakpoint-md) {
    justify-content: flex-start;
  }
}

.pulse-dot {
  width: 8px;
  height: 8px;
  background: #22c55e;
  border-radius: 50%;
  animation: pulse-status 2s ease-in-out infinite;
  position: relative;

  &::before {
    content: '';
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    background: #22c55e;
    border-radius: 50%;
    opacity: 0.3;
    animation: pulse-ring 2s ease-in-out infinite;
  }
}

@keyframes pulse-status {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.6; }
}

@keyframes pulse-ring {
  0%, 100% { 
    transform: scale(1);
    opacity: 0.3; 
  }
  50% { 
    transform: scale(1.5);
    opacity: 0; 
  }
}

.pulse-text {
  font-size: $font-size-xs;
  color: $text-tertiary;
  font-weight: $font-weight-medium;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}


// Site footer styling
footer {
  padding: 2rem 0; // Design system desktop spacing (32px)
  background: #fefcfa;
  border-top: 1px solid rgba(230, 228, 223, 0.2);
  margin-top: 2rem; // Reduced margin for ultra-tight aesthetic

  @media (max-width: $breakpoint-sm) {
    padding: 1.5rem 0; // Design system mobile spacing (24px)
    margin-top: 1.5rem; // Consistent with mobile spacing
  }

  small {
    display: block;
    text-align: center;

    > div {
      display: flex;
      justify-content: center;
      gap: 2rem;
      align-items: center;

      @media (max-width: 48rem) {
        gap: 1.5rem;
      }
    }

    a {
      opacity: 0.7;
      transition: opacity 0.2s ease;

      &:hover {
        opacity: 1;
      }
    }
  }
}


// Hero reveal animation keyframes
@keyframes heroReveal {
  0% {
    opacity: 0;
    transform: translateY(30px) scale(0.98);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}


// Underline grow animation for emphasized text
@keyframes underlineGrow {
  0% {
    transform: scaleX(0);
    opacity: 0;
  }
  100% {
    transform: scaleX(1);
    opacity: 0.4;
  }
}

// Subtle hover effects for interactive elements
.hero-links {
  .btn {
    transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);

    &:hover {
      transform: translateY(-2px);
      box-shadow: 0 8px 25px rgba(0, 0, 0, 0.1);
    }

    &:active {
      transform: translateY(0);
    }
  }
}
